"use client";

export default function ShinyText({ text, disabled = false, speed = 5, className = '' }) {
  const animationDuration = `${speed}s`;

  return (
    <span
      className={`text-[#b5b5b5a4] bg-[linear-gradient(120deg,rgba(255,255,255,0)_40%,rgba(255,255,255,0.8)_50%,rgba(255,255,255,0)_60%)] bg-[length:200%_100%] bg-clip-text animate-shine will-change-[background-position] ${
        disabled ? '' : 'animate-shiny'
      } ${className}`}
      style={{ animationDuration }}
    >
      {text}
    </span>
  );
}